#!/bin/bash\n# Poth Foliyo - Quick Setup Script\n\necho \"🎨 Poth Foliyo - Portfolio Setup\"\necho \"================================\"\necho \"\"\n\n# Check if Node.js is installed\nif ! command -v node &> /dev/null; then\n    echo \"❌ Node.js is not installed.\"\n    echo \"Please install Node.js from https://nodejs.org/\"\n    exit 1\nfi\n\necho \"✅ Node.js version: $(node --version)\"\necho \"✅ NPM version: $(npm --version)\"\necho \"\"\n\necho \"📦 Installing dependencies...\"\necho \"\"\n\n# Install root dependencies\necho \"Installing root dependencies...\"\nnpm install\n\n# Install server dependencies\necho \"\"\necho \"Installing server dependencies...\"\ncd server\nnpm install\ncd ..\n\n# Install client dependencies\necho \"\"\necho \"Installing client dependencies...\"\ncd client\nnpm install\ncd ..\n\necho \"\"\necho \"✅ Installation complete!\"\necho \"\"\necho \"📋 Next steps:\"\necho \"\"\necho \"1. Setup MongoDB\"\necho \"   - Ensure MongoDB is running locally or use MongoDB Atlas\"\necho \"   - Update server/.env with your MONGO_URI if needed\"\necho \"\"\necho \"2. Start the server:\"\necho \"   cd server && npm run dev\"\necho \"\"\necho \"3. In another terminal, start the client:\"\necho \"   cd client && npm run dev\"\necho \"\"\necho \"4. Open http://localhost:5173/ in your browser\"\necho \"\"\necho \"For more details, see SETUP_GUIDE.md\"\n